command.text:
&CommandCheckTaxCodeBeforeSave;
if exists(select * from @@table where ma_ns = @ma_ns) begin select 'ma_ns' as field, replace(@$exists, '%s', rtrim(@ma_ns)) as message return end if exists(select * from @@table where (ma_ns like rtrim(@ma_ns) + '%') or (@ma_ns like rtrim(ma_ns) + '%')) begin select 'ma_ns' as field, replace(@$exists, '%s', rtrim(@ma_ns)) as message return end select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID update @d1 set ma_ns = @ma_ns, luong_cb = luong_cb_nt, gt_bhnn = gt_bhnn_nt, gt_khac = gt_khac_nt update @d2 set ma_ns = @ma_ns update @d3 set ma_ns = @ma_ns update @d4 set ma_ns = @ma_ns
&CommandListCheckTaxCodeWarning;

        /* <flatten type="Javascript"> */
var f = this, g1 = f.getItem("d1")._controlBehavior, g2 = f.getItem("d2")._controlBehavior, g3 = f.getItem('d3')._controlBehavior, g4 = f.getItem('d4')._controlBehavior;
if (f._checked && g4._rowCount > 1) check$PITForm$Duplicate(f, g4, 'd4', 'ngay_hl');
if (f._checked) check$PITForm$DataGrid(f, g1, 'd1', 'ngay_hl_tu', 'ngay_hl_den');
if (f._checked) check$PITForm$DataGrid(f, g2, 'd2', 'ngay_hl_tu', 'ngay_hl_den', 'ma_pt');
if (f._checked && g3._rowCount > 1) check$PITForm$Duplicate(f, g3, 'd3', 'ngay_hl');
/* </flatten> */

script.text:
      &OutlineEntry;
      &ScriptCheckTaxCode;
      /* <flatten type="Javascript"> */
function load$FormPersonal(f) {
  f.add_commandEvent(on$FormPersonal$ExecuteCommand);
  f.add_onResponseComplete(on$FormPersonal$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$Form$Tab);
  f._tabContainer._loaded = true;
  setDefaultValue(f);
  validAuthorization(f);
}

function close$FormPersonal(f) {
  try {f.remove_commandEvent(on$FormPersonal$ExecuteCommand);} catch (ex) {}
  try {if (f._tabContainer) f._tabContainer.remove_activeTabChanged(onChange$Form$Tab);} catch (ex) {}
  try {f.remove_onResponseComplete(on$FormPersonal$ResponseComplete)} catch (ex) {}
}
function scatter$FormPersonal(f) {
  setDefaultValue(f);
  validAuthorization(f);
}
function onChange$Form$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ngay_sinh', 'd4', 'd1', 'd2', 'd3', 'ghi_chu']);}
function on$FormPersonal$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_ns');
      break;
    default:
      break;
  }
}
function on$FormPersonal$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d3')._controlBehavior, w = f.getItem('d4')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');

      w.setSequenceNumber('line_nbr');
      w.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
function onChange$Object(o) {window.setTimeout(String.format('validAuthorization(null,\'{0}\');', o.parentForm._id), 2);}
function onChange$Contract(o) {window.setTimeout(String.format('validAuthorization(null,\'{0}\');', o.parentForm._id), 2);}
function validAuthorization(f, id) {
  if (f == null) f = $find(id);
  if (f == null) return;
  var o = f.getItem('uy_quyen_yn'), v = f.getItem('bhxh_yn');
  if (f.getItemValue('doi_tuong') == 1 && f.getItemValue('hop_dong_yn') == 1) {
    o.disabled = false;
    if (v.live) o.focus();
  }
  else {
    o.value = 0;
    o.disabled = true
    if (o.live) v.focus();
  }
}
function setDefaultValue(f) {if (f._action == 'New') f.setItemValues('ma_dvcs, ten_dvcs%l', [f._unit, f._unitName]);}
function check$PITForm$DataGrid(f, g, d, s1, s2, s3) {
  var id = f.get_id(), gID = g.get_id(), v = f._language == 'v';
  var e1 = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> phải nhỏ hơn trường <span class="Highlight">Đến ngày</span>.' : '<span class="Highlight">Effective from</span> must be less than <span class="Highlight">Effective to</span>.');
  var e2 = (v ? 'Trường <span class="Highlight">Hiệu lực đến ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective to</span> must not be blank or has invalid value.');
  var e3 = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective from</span> must not be blank or has invalid value.');

  var t1 = g._getColumnOrder(s1), t2 = g._getColumnOrder(s2);
  for (var i = 1; i <= g._rowCount; i++) {
    var d1 = g._getItemValue(i, t1), d2 = g._getItemValue(i, t2);
    if (d2 != null) {
      if (d1 > d2) {
        g._errorWarningObject = g._getItem(i, t2);
        $func.hideWait(id);
        $message.show(e1, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
        f._checked = false;
        break;
      }
    }

    if (f._checked && i < g._rowCount) {
      var n = i;
      if (s3 != null) {
        var k = g._getColumnOrder(s3), c = g._getItemValue(i, k);
        for (var j = i + 1; j <= g._rowCount; j++) {
          if (g._getItemValue(j, k) == c) {n = j; break;}
        }
      } else n += 1;

      if (n > i && !d2) {
        g._errorWarningObject = g._getItem(i, t2);
        $func.hideWait(id);
        $message.show(e2, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
        f._checked = false;
        break;
      }

      if (f._checked && n > i) {
        var d3 = g._getItemValue(n, t1);
        if (d2 >= d3) {
          g._errorWarningObject = g._getItem(n, t1);
          $func.hideWait(id);
          $message.show(e3, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
          f._checked = false;
          break;
        }
      }
    }
  }
}
function check$PITForm$Duplicate(f, g, d, s) {
  var id = f.get_id(), gID = g.get_id(), v = f._language == 'v', t = g._getColumnOrder(s);
  var e = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective from</span> must not be blank or has invalid value.');
  for (var i = 1; i < g._rowCount; i++) {
    if (!f._checked) break;
    for (var j = i + 1; j <= g._rowCount; j++) {
      var d1 = g._getItemValue(i, t).valueOf(), d2 = g._getItemValue(j, t).valueOf();
      if (d1 == d2) {
        g._errorWarningObject = g._getItem(j, t);
        $func.hideWait(id);
        $message.show(e, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
        f._checked = false;
        break;
      }
    }
  }
}
/* </flatten> */
      &ScriptIrregular;
